ets[0].data[i];\n                if (value > 0) {\n                  c.fillStyle = \"#374151\";\n                  c.fillText(value, bar.x, bar.y - 6);\n                }\n              });\n              c.restore();\n            },\n          },\n        ],\n      });\n    },\n  },\n};\n</script>\n\n<style scoped>\n.bar-chart {\n  position: relative;\n  width: 100%;\n  height: 250px;\n}\n\n.bar-chart canvas {\n  width: 100% !important;\n  height: 100% !important;\n}\n\n.bar-chart__empty {\n  width: 100%;\n  height: 250px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border: 2px dashed var(--color-border, #e5e7eb);\n  border-radius: 12px;\n}\n\n.bar-chart__empty-text {\n  font-size: 14px;\n  color: var(--color-text-secondary, #6b7280);\n  font-weight: 500;\n}\n</style>\n"],"sourceRoot":""}]);
